```java
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

class Solution {
    public int[] topKFrequent(int[] nums, int k) {
        // Step 1: Count the frequency of each number using a HashMap.
        Map<Integer, Integer> freqMap = new HashMap<>();
        for (int num : nums) {
            freqMap.put(num, freqMap.getOrDefault(num, 0) + 1);
        }

        // Step 2: Create an array of lists (buckets) where the index represents the frequency.
        // buckets[i] will store all numbers that appear 'i' times.
        // The maximum possible frequency is nums.length.
        List<Integer>[] buckets = new List[nums.length + 1];

        // Step 3: Populate the buckets with numbers based on their frequencies.
        for (Map.Entry<Integer, Integer> entry : freqMap.entrySet()) {
            int num = entry.getKey();
            int freq = entry.getValue();
            if (buckets[freq] == null) {
                buckets[freq] = new ArrayList<>();
            }
            buckets[freq].add(num);
        }

        // Step 4: Collect the top K frequent elements by iterating buckets from highest frequency to lowest.
        List<Integer> resultList = new ArrayList<>();
        // Iterate from the highest possible frequency down to 1.
        for (int i = nums.length; i >= 1 && resultList.size() < k; i--) {
            if (buckets[i] != null) {
                for (int num : buckets[i]) {
                    resultList.add(num);
                    if (resultList.size() == k) {
                        break; // Found K elements, no need to continue.
                    }
                }
            }
        }

        // Convert the List<Integer> to int[] as required by the problem.
        int[] resultArray = new int[k];
        for (int i = 0; i < k; i++) {
            resultArray[i] = resultList.get(i);
        }

        return resultArray;
    }
}
