class Solution {
    public int[] productExceptSelf(int[] nums) {
        int n = nums.length;
        int[] result = new int[n];

        // Pass 1: Calculate prefix products
        // result[i] will contain the product of all elements to the left of i
        // For index 0, there are no elements to the left, so the product is 1.
        result[0] = 1;
        for (int i = 1; i < n; i++) {
            result[i] = result[i - 1] * nums[i - 1];
        }

        // Pass 2: Calculate suffix products and combine with prefix products
        // rightProduct will store the product of all elements to the right of the current index
        int rightProduct = 1;
        for (int i = n - 1; i >= 0; i--) {
            // For the current index i, result[i] already holds the product of elements to its left.
            // We multiply it by the product of elements to its right (rightProduct).
            result[i] = result[i] * rightProduct;
            // Update rightProduct for the next iteration (to the left)
            rightProduct = rightProduct * nums[i];
        }

        return result;
    }
}
