class Solution {
    public int maxProduct(int[] nums) {
        if (nums == null || nums.length == 0) {
            return 0;
        }

        // max_so_far stores the maximum product ending at the current position
        // min_so_far stores the minimum product ending at the current position
        int max_so_far = nums[0];
        int min_so_far = nums[0];
        // result stores the overall maximum product found so far
        int result = nums[0];

        for (int i = 1; i < nums.length; i++) {
            int curr = nums[i];
            // We need to store max_so_far from the previous step
            // because it will be used to calculate both new max_so_far and new min_so_far
            // and max_so_far itself will be updated first.
            int temp_max = max_so_far;

            max_so_far = Math.max(curr, Math.max(temp_max * curr, min_so_far * curr));
            min_so_far = Math.min(curr, Math.min(temp_max * curr, min_so_far * curr));

            result = Math.max(result, max_so_far);
        }

        return result;
    }
}

