class Solution {
    public boolean isValidSudoku(char[][] board) {
        // Three boolean arrays to keep track of seen numbers in rows, columns, and 3x3 subgrids.
        // The first dimension (0-8) represents the row/column/box index.
        // The second dimension (0-8) represents the digit (e.g., '1' maps to index 0, '9' maps to index 8).
        boolean[][] rows = new boolean[9][9];
        boolean[][] cols = new boolean[9][9];
        boolean[][] boxes = new boolean[9][9]; // For 3x3 subgrids

        for (int i = 0; i < 9; i++) {
            for (int j = 0; j < 9; j++) {
                char c = board[i][j];

                if (c != '.') {
                    int num = c - '1'; // Convert char '1'-'9' to int 0-8

                    // Check row
                    if (rows[i][num]) {
                        return false;
                    }
                    rows[i][num] = true;

                    // Check column
                    if (cols[j][num]) {
                        return false;
                    }
                    cols[j][num] = true;

                    // Check 3x3 subgrid
                    // Calculate the index for the current 3x3 box
                    // There are 9 boxes, indexed from 0 to 8
                    // Example: (0,0) -> box 0, (0,3) -> box 1, (3,0) -> box 3
                    int boxIndex = (i / 3) * 3 + (j / 3);
                    if (boxes[boxIndex][num]) {
                        return false;
                    }
                    boxes[boxIndex][num] = true;
                }
            }
        }

        return true;
    }
}
